const schema = {
  type: 'object',
  properties: {
    invoiceNumber: { type: 'string' },
    date: { type: 'string', format: 'date' },
    totalAmount: { type: 'number' },
    lineItems: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          description: { type: 'string' },
          quantity: { type: 'number' },
          unitPrice: { type: 'number' }
        }
      }
    }
  },
  required: ['invoiceNumber', 'totalAmount']
};

// AI Agent prompt
return {
  json: {
    instruction: `Extract invoice data from this document as valid JSON matching the schema. Document: ${{ $json.document }}`,
    schema: schema
  }
};

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

const result = await vex.verify({
  input: {
    document: items[0].json.document,
    extractedData: items[0].json.extracted
  },
  checks: [
    {
      type: 'json_schema',
      name: 'invoice_schema_compliance',
      schema: {
        type: 'object',
        properties: {
          invoiceNumber: { type: 'string' },
          totalAmount: { type: 'number', minimum: 0 }
        },
        required: ['invoiceNumber']
      },
      path: '$.extractedData'
    }
  ]
});

return {
  verified: result.passed,
  issues: result.issues,
  data: result.output
};

const checks = [
  {
    type: 'field_accuracy',
    name: 'total_amount_verification',
    path: '$.extractedData.totalAmount',
    groundTruth: '={{ $json.document }}',
    threshold: 0.95,
    metric: 'semantic_similarity'
  },
  {
    type: 'completeness',
    name: 'required_fields_present',
    path: '$.extractedData',
    requiredFields: ['invoiceNumber', 'date', 'lineItems']
  }
];

const result = await vex.verify({
  input: items[0].json,
  checks: checks
});

if (!result.passed) {
  throw new Error(`Extraction failed validation: ${JSON.stringify(result.issues)}`);
}

return result.output;

const typeChecks = [
  {
    type: 'type_consistency',
    name: 'numeric_fields_valid',
    path: '$.extractedData.totalAmount',
    expectedType: 'number'
  },
  {
    type: 'array_length',
    name: 'line_items_minimum',
    path: '$.extractedData.lineItems',
    minLength: 1,
    maxLength: 50
  },
  {
    type: 'regex_match',
    name: 'invoice_number_format',
    path: '$.extractedData.invoiceNumber',
    pattern: '^INV-\d{6}$'
  }
];

return await vex.verify({
  input: items[0].json,
  checks: typeChecks,
  policy: 'block_on_failure'
});

